import { Mutex } from "async-mutex";
import { performance } from "perf_hooks";
import * as vscode from "vscode";
import { InlineCompletionContext } from "vscode";
import { POST_ACCEPTANCE_COMMAND } from "./commands/ids";
import { CompletionService } from "../services/completion";
import {
  CompletionState,
  penalizedLogConfidence,
} from "../resultCache/completionState";
import Settings from "../services/settings/settings";
import { ILoggingService, LogLevel } from "../services/logging";
import { INormalizationService } from "../services/normalization";
import { isAlphanumeric } from "../utils/document";
import { matchBraces } from "../utils/postProcRules";
import { FaultType, Telemetry } from "../services/telemetry/vscodeTelemetry";
import { getTextDocContext, getNotebookContext } from "../utils/vscodeEditor";
import {
  TelemetryEventNames,
  TelemetryMeasureNames,
  TelemetryPropertyNames,
} from "../@types/telemetry";
import { ParsedCode } from "../services/normalization/normalizationService";

import { processCompletion } from "../utils/inlineCompletionProvider/processCompletionItem";

import {
  isSyntacticallyCorrect,
  isUniqueLine,
} from "../utils/inlineCompletionProvider/validateCompletionItem";
import { TreeSitterSyntacticFilterService } from "../services/syntacticFilter/treeSitterSyntacticFilter";
import {
  ExtendedInlineCompletionItem,
  postAcceptanceCommandArguments,
  PreviousCompletionItemProvided,
} from "../@types/inlineCompletionProvider";

import {
  walkingThePredictionStatus,
  modifyPreviousCompletionProvided,
  hasDocumentChanged,
  hasLineNumberChanged,
} from "../utils/inlineCompletionProvider/walkingThePrediction";
import {
  FeedbackSurveyService,
  USER_IN_REST_STATE_TIME,
} from "../services/survey";

/**
 * These are characters that we consider acceptable for the suggestion to start with
 * when the context ends on a whitespace.
 * Most tokens, even including brackets and parenthesis, will have a space prepended.
 * We just added the parenthesis and brackets in as a safety measure.
 */
const whitespaceAllowed = new Set([" ", "(", "{", "["]);

export function createAcceptCommand(
  postAcceptanceCommandArguments: postAcceptanceCommandArguments
) {
  return {
    command: POST_ACCEPTANCE_COMMAND,
    title: "Send Acceptance Telemetry",
    arguments: [postAcceptanceCommandArguments],
  } as vscode.Command;
}

/**
 * Implements vscode.InlineCompletionItemProvider- this is what VSCode calls when
 * we need to provide a gray-text completion.
 */
export class IntelliCodeInlineCompletionItemProvider
  implements vscode.InlineCompletionItemProvider {
  /**
   * Timestamp of the last call to this provider.
   * Used to keep track of how frequent calls to this provider is.
   */
  private lastCallTime = performance.now();

  /**
   * Enforces only a single model inference to be running at a given time.
   */
  private inferenceLock = new Mutex();

  /**
   * Assign each request a unique id for debugging purposes.
   */
  private requestId = 0;
  private prevCompletionProvided: PreviousCompletionItemProvided | undefined;
  private timeout: NodeJS.Timeout | undefined;

  constructor(
    private normalizationService: INormalizationService,
    private syntacticFilter: TreeSitterSyntacticFilterService,
    private loggingService: ILoggingService,
    private telemetry: Telemetry,
    private completionState: CompletionState,
    private lineCompletionService: CompletionService,
    private settings: Settings,
    private extensionContext: vscode.ExtensionContext | undefined
  ) { }

  /**
   * This method runs *after* the completion item is shown to the user
   */
  public handleDidShowCompletionItem(
    inlineCompletionItem: vscode.InlineCompletionItem
  ) {
    if (this.extensionContext != undefined) {
      const feedbackSurveyService = new FeedbackSurveyService(this.extensionContext);
      feedbackSurveyService.initializeGlobalStateKeys();
      // All our completion items are ExtendedInlineCompletionItem, so assert the type.
      const item = inlineCompletionItem as ExtendedInlineCompletionItem;

      if (item.shouldSendTelemetry) {
        this.telemetry?.sendTelemetryEvent(
          TelemetryEventNames.COMPLETION_SHOWN,
          item.properties ?? {},
          item.measures ?? {}
        );
      }

      feedbackSurveyService.incrementNumberOfCompletionsShown();

      if (this.timeout) {
        clearTimeout(this.timeout);
      }
      // Show the notification only when the user has been inactive for some time
      this.timeout = setTimeout(() => {
        feedbackSurveyService.showToastNotification();
      }, USER_IN_REST_STATE_TIME);
    }
  }

  public async provideInlineCompletionItems(
    document: vscode.TextDocument,
    position: vscode.Position,
    completionContext: InlineCompletionContext,
    cancellationToken: vscode.CancellationToken
  ): Promise<
    | vscode.InlineCompletionList
    | vscode.InlineCompletionItem[]
    | null
    | undefined
  > {
    // Only get inline completion items for enabled languages.
    if (!this.settings.getLanguageEnabled(document.languageId)) {
      return undefined;
    }

    const logPrefix = `[inlineCompletionProvider.provideInlineCompletionItems() ${this.requestId}] `;
    this.requestId += 1;

    // https://github.com/microsoft/vscode/issues/147414
    const associatedNotebook = vscode.workspace.notebookDocuments.find(
      (notebook) =>
        notebook.getCells().some((cell) => cell.document === document)
    );
    const isNotebook = !!associatedNotebook;

    try {
      this.loggingService.write(
        LogLevel.DEBUG,
        `${logPrefix} Entered provideInlineCompletionItems() try block`
      );

      const providerCalledTime = performance.now();

      const timeSinceLastProvide = providerCalledTime - this.lastCallTime;
      this.telemetry.sendTelemetryEvent(
        TelemetryEventNames.COMPLETION_PROVIDER_CALLED,
        {},
        {
          [TelemetryMeasureNames.TIME_SINCE_LAST_PROVIDE]: timeSinceLastProvide,
        }
      );
      this.lastCallTime = providerCalledTime;

      cancellationToken.onCancellationRequested((e) => {
        const providerCancelRequestTime = performance.now();
        const timeTillCancel = providerCancelRequestTime - providerCalledTime;

        this.loggingService.write(
          LogLevel.INFO,
          `${logPrefix} Recieved cancellation event, ran for ${timeTillCancel}`
        );

        this.telemetry.sendTelemetryEvent(
          TelemetryEventNames.COMPLETION_PROVIDER_CANCEL_REQUESTED,
          {},
          {
            [TelemetryMeasureNames.TIME_TIL_CANCEL_REQ]: timeTillCancel,
          }
        );
      });

      const documentLanguage = document.languageId;

      if (!this.normalizationService.isAvailableFor(documentLanguage)) {
        await this.normalizationService.initialize(documentLanguage);
      }

      if (cancellationToken.isCancellationRequested) {
        this.loggingService.write(LogLevel.DEBUG, `${logPrefix} Cancelled`);
        return undefined;
      }
      /**
       * Code in the document
       */
      const codeBefore = isNotebook
        ? getNotebookContext(
          associatedNotebook,
          document,
          position,
          completionContext
        )
        : getTextDocContext(document, position, completionContext);
      /**
       * Code in the line
       */
      const codeOnLine = document.lineAt(position.line).text;

      /**
       * Code on line till the cursor
       */
      const codeTillCursor = codeOnLine.substring(0, position.character);

      if (this.prevCompletionProvided) {
        const isUserWalkingThePrediction = walkingThePredictionStatus(
          hasDocumentChanged(
            this.prevCompletionProvided.prevDocument,
            document
          ),
          hasLineNumberChanged(
            this.prevCompletionProvided.prevLine,
            position.line
          ),
          completionContext.selectedCompletionInfo?.text,
          this.prevCompletionProvided.prevSelectedCompletion,
          this.prevCompletionProvided.prevFullLineCompletion,
          codeOnLine,
          codeTillCursor
        );

        if (isUserWalkingThePrediction) {
          this.loggingService.write(
            LogLevel.DEBUG,
            `${logPrefix} User is walking the prediction`
          );
          const modifiedPreviousCompletionProvided =
            modifyPreviousCompletionProvided(
              this.prevCompletionProvided.prevFullLineCompletion,
              this.prevCompletionProvided.prevSnippetString,
              this.prevCompletionProvided.prevSnippetRange,
              this.prevCompletionProvided.prevCompletionItem.insertText,
              this.prevCompletionProvided.prevCompletionItem.range,
              codeOnLine,
              position.line
            );
          this.prevCompletionProvided.prevCompletionItem.insertText =
            modifiedPreviousCompletionProvided.newCompletionText;
          this.prevCompletionProvided.prevCompletionItem.range =
            modifiedPreviousCompletionProvided.newCompletionRange;

          // Do not send multiple telemetry events when user is walking the prediction
          this.prevCompletionProvided.prevCompletionItem.shouldSendTelemetry = false;

          // Updating arguments for postAcceptanceCommand here
          let modifiedCommandArguments: postAcceptanceCommandArguments =
            this.prevCompletionProvided.prevCompletionItem.command!
              .arguments![0];

          modifiedCommandArguments.postInsertionString =
            modifiedPreviousCompletionProvided.newSnippetText;
          modifiedCommandArguments.overwriteRange =
            modifiedPreviousCompletionProvided.newSnippetRange;
          this.prevCompletionProvided.prevCompletionItem.command!.arguments![0] =
            modifiedCommandArguments;

          return new vscode.InlineCompletionList([
            this.prevCompletionProvided.prevCompletionItem,
          ]);
        } else {
          this.prevCompletionProvided = undefined;
        }
      }

      let parsedCode: ParsedCode | undefined;
      let normCodeBefore: string | undefined;

      try {
        parsedCode = this.normalizationService.parse(
          codeBefore,
          documentLanguage
        );
        normCodeBefore = this.normalizationService.normalize(parsedCode);

        if (!normCodeBefore) {
          // We're most likely writing a comment right now, and we do not want to run extension.
          return undefined;
        }
      } catch (e) {
        this.loggingService.write(
          LogLevel.ERROR,
          `${logPrefix} Error during normalization: ${e}`
        );
        return undefined;
      }

      if (cancellationToken.isCancellationRequested) {
        this.loggingService.write(LogLevel.DEBUG, `${logPrefix} Cancelled`);
        return undefined;
      }

      const request: boolean =
        !cancellationToken.isCancellationRequested &&
        codeBefore.length > 0 &&
        (!isAlphanumeric(codeBefore.charCodeAt(codeBefore.length - 1)) ||
          completionContext.selectedCompletionInfo !== undefined); // Trigger inference if the user has a selected item in the suggestions widget/completion menu

      // Optimization: Try to heuristically guess the last 256 tokens. This way BlingFire doesn't have to tokenize entire file.
      normCodeBefore = shortenContextOnSpaces(
        normCodeBefore,
        this.settings.TOKEN_LOOKBACK
      )

      if (request) {
        this.loggingService.write(
          LogLevel.DEBUG,
          `${logPrefix}Starting request`
        );

        const beforeLock = performance.now();

        /**
         * This lock ensures that only one inference is running at a time..
         *
         * Without this once the user types fast enough,
         * multiple inference instances will be proc'd at the same time leading to a lag spike.
         *
         * Another solution that was tested was honoring the cancellation token within onnxModelWrapper.
         * This solution stopped farther inferences once a token was marked as cancelled,
         * but had the problem of leading to inconsistent recommendations
         * as each inference would lead to a different number of tokens being produced.
         */

        const release = await this.inferenceLock.acquire();
        const afterLock = performance.now();
        if (cancellationToken.isCancellationRequested) {
          this.loggingService.write(
            LogLevel.DEBUG,
            logPrefix + `Cancelled after ${afterLock - beforeLock}ms wait`
          );
          release();
          return undefined;
        }
        try {
          await this.lineCompletionService.request(
            this.requestId,
            normCodeBefore,
            documentLanguage,
            this.completionState,
            { isCancellationRequested: false }
          );
        } catch (e) {
          this.loggingService.write(
            LogLevel.ERROR,
            `${logPrefix} Caught error when requesting inline completion: ${e}`
          );
          throw e;
        } finally {
          release();
          this.loggingService.write(
            LogLevel.INFO,
            `${logPrefix}\n\t` +
            `Wait: ${afterLock - beforeLock}ms\n\t` +
            `Full inference: ${performance.now() - afterLock}`
          );
        }
      } else {
        this.loggingService.write(
          LogLevel.DEBUG,
          `${logPrefix}Skipping request`
        );
      }
      if (cancellationToken.isCancellationRequested) {
        return undefined;
      }

      const {
        bestCompletion: completion,
        metadata: { firstTokenScore, cumulativeLastScore, tokenCount },
      } = this.completionState.getLineCompletion(
        normCodeBefore,
        this.settings.getFirstTokenConfidenceThreshold(documentLanguage),
        Number.NEGATIVE_INFINITY /* Deactivating Log Cutoff after cache schema change to individual token probability */
      );

      // const a vs const a_
      // Check if last whitespace exists, and if the recommendation makes sense w/ it in mind
      if (
        !document.lineAt(position.line).isEmptyOrWhitespace &&
        codeBefore.endsWith(" ") &&
        !whitespaceAllowed.has(completion.charAt(0))
      ) {
        this.loggingService.write(
          LogLevel.INFO,
          `${logPrefix} Ignoring completion as it did not start w/ a whitespace:\n\t` +
          completion
        );
        return undefined;
      }

      // Check if indentation level is at a place where we want to show suggestions
      // WARNING: E2E TESTS CAN FAIL IF YOU HAVE AN OPENED DOCUMENT IN THE EXTENSION HOST
      const { activeTextEditor } = vscode.window;
      if (activeTextEditor) {
        if (activeTextEditor.document !== document) {
          // Defensive coding
          this.loggingService.write(
            LogLevel.FATAL,
            logPrefix +
            `Active text editor and document mismatch, returning undefined.`
          );
          return undefined;
        }

        if (
          !correctlyIndented(
            completion,
            document,
            position,
            +(activeTextEditor.options.tabSize || "4") // +() syntax casts to number
          )
        ) {
          this.loggingService.write(
            LogLevel.INFO,
            logPrefix +
            `Suggestion triggered on wrong indentation level, returning undefined.`
          );
          return undefined;
        }
      }

      const codeTillSelectedCompletion = completionContext.selectedCompletionInfo
        ? codeOnLine.substring(
          0,
          completionContext.selectedCompletionInfo.range.start.character
        )
        : undefined;

      const {
        completionToReturn,
        snippetToReturn,
        additionalData: {
          fullLineWithCompletion,
          fullLineWithSnippet,
          postAcceptanceRange,
          completionRange,
          snippetCount,
        },
      } = processCompletion(
        codeTillCursor,
        codeTillSelectedCompletion,
        completionContext.selectedCompletionInfo?.text,
        completionContext.selectedCompletionInfo?.range,
        position,
        completion
      );

      if (
        !isUniqueLine(
          fullLineWithCompletion,
          document,
          position,
          this.loggingService,
          logPrefix
        )
      ) {
        return undefined;
      }

      if (this.settings.PARSE_ERROR_FILTER) {
        // try to parse result
        if (
          !isSyntacticallyCorrect(
            fullLineWithCompletion,
            postAcceptanceRange,
            document,
            position,
            parsedCode,
            this.normalizationService,
            this.syntacticFilter,
            this.loggingService,
            logPrefix
          )
        ) {
          return undefined;
        }
      }

      const items: vscode.InlineCompletionItem[] = [];

      let postAcceptanceInsertion = "";
      if (
        this.settings.SNIPPET_COMPLETION &&
        completionToReturn !== snippetToReturn
      ) {
        // Prepare snippet to overwrite entire completion
        postAcceptanceInsertion += snippetToReturn;
      }
      if (this.settings.BRACE_COMPLETION) {
        this.loggingService.write(
          LogLevel.DEBUG,
          `${logPrefix} Matching braces in completion`
        );
        const requiredBraces = matchBraces(completionToReturn);
        postAcceptanceInsertion += `$0${requiredBraces}`;
      }

      const lengthPenalizedLastTokenScore = penalizedLogConfidence(
        cumulativeLastScore,
        tokenCount,
        this.settings.WLC_RECOMMENDATION_LENGTH_PENALTY
      );

      const postAcceptanceCommandArguments: postAcceptanceCommandArguments = {
        languageId: document.languageId,
        completionLength: completionToReturn.length,
        firstTokenScore: firstTokenScore,
        cumulativeLastTokenScore: cumulativeLastScore,
        tokenCount: tokenCount,
        lengthPenalizedLastTokenScore: lengthPenalizedLastTokenScore,
        snippetPlaceholderCount: snippetCount,
        editor: activeTextEditor,
        postInsertionString: postAcceptanceInsertion,
        overwriteRange: postAcceptanceRange,
        [Symbol.toStringTag]: "PostAcceptanceCommandArgumentsTag",
      };

      const completionItem: ExtendedInlineCompletionItem = {
        insertText: completionToReturn,
        range: completionRange,
        command: createAcceptCommand(postAcceptanceCommandArguments),
        shouldSendTelemetry: true,
        properties: {
          [TelemetryPropertyNames.LANGUAGE_ID]: document.languageId,
        },
        measures: {
          [TelemetryMeasureNames.COMPLETION_LENGTH]: completionToReturn.length,
          [TelemetryMeasureNames.FIRST_TOKEN_SCORE]: firstTokenScore,
          [TelemetryMeasureNames.CUMULATIVE_LAST_TOKEN_SCORE]:
            cumulativeLastScore,
          [TelemetryMeasureNames.TOKEN_COUNT]: tokenCount,
          [TelemetryMeasureNames.LENGTH_PENALIZED_LAST_TOKEN_SCORE]:
            lengthPenalizedLastTokenScore,
          [TelemetryMeasureNames.SNIPPET_PLACEHOLDER_COUNT]: snippetCount,
        },
      };

      items.push(completionItem);

      // Updating last provided prediction

      this.prevCompletionProvided = {
        prevFullLineCompletion: fullLineWithCompletion,
        prevCompletionItem: completionItem,
        prevDocument: document,
        prevLine: position.line,
        prevSnippetString: fullLineWithSnippet,
        prevSnippetRange: postAcceptanceRange,
        prevSelectedCompletion: completionContext.selectedCompletionInfo?.text,
      };

      if (
        isPredictionAddingOnlyWhitespace(
          fullLineWithCompletion,
          document.lineAt(position).text
        )
      ) {
        this.loggingService.write(
          LogLevel.DEBUG,
          `${logPrefix} Skipping prediction because it only adds/removes whitespaces`
        );
        return undefined;
      }

      this.telemetry?.sendTelemetryEvent(
        TelemetryEventNames.COMPLETION_SENT,
        completionItem.properties ?? {},
        completionItem.measures ?? {}
      );

      return new vscode.InlineCompletionList(items);
    } catch (e) {
      if (e instanceof Error) {
        this.loggingService?.write(
          LogLevel.ERROR,
          `${logPrefix}Unexpected exception: ${e.message}\n${e.stack}`
        );

        this.telemetry.sendFault(
          TelemetryEventNames.UNEXPECTED_EXCEPTION,
          FaultType.Unknown,
          e.message,
          e,
          undefined
        );
      }
    }
  }
}

function isPredictionAddingOnlyWhitespace(
  prediction: string,
  currLine: string
) {
  const predictionWithoutWhitespace = prediction.replace(/\s+/g, "");
  const currLineWithoutWhitespace = currLine.replace(/\s+/g, "");
  if (predictionWithoutWhitespace === currLineWithoutWhitespace) {
    return true;
  }
  return false;
}

/**
 * Heuristic used to check that the suggestions were triggered on the "correct" indentation level.
 * To determine this, the <INDENT>, <DEDENT> tokens are taken into consideration.
 *
 * Instead of having a single correct position for the suggestion,
 * this checks if the position is at least a certain indentation level.
 * Defining a single correct position made it so that the UX felt like a hide-and-seek with the suggestion.
 *
 * @param completion Suggested completion with <INDENT>, <DEDENT> tokens
 * @param document The VSCode document to provide suggestions to
 * @param pos Location of the cursor when suggestions were triggered
 * @param indentSize The indent size to use
 * @return True if current indentation "correct"
 */
function correctlyIndented(
  completion: string,
  document: vscode.TextDocument,
  pos: vscode.Position,
  indentSize: number = 4
): boolean {
  if (pos.line === 0) {
    // We should not assume indentation level on the very first line
    return true;
  }
  const prevIndent = document.lineAt(
    pos.line - 1
  ).firstNonWhitespaceCharacterIndex;

  if (completion.startsWith("<INDENT>")) {
    // First count how many <INDENT> are there at the start
    const indents = getNumberOfRepeatsAtStart(completion, "<INDENT>");

    // Consider correct if indented the correct amount of times or more
    // Purposefully loosely adhering to account for different code formatting
    return pos.character >= prevIndent + indents * indentSize;
  } else if (completion.startsWith("<DEDENT>")) {
    // First count how many <DEDENT> are there at the start
    const dedents = getNumberOfRepeatsAtStart(completion, "<DEDENT>");

    // Consider correct if dedented the correct amount of times or more
    // Purposefully loosely adhering to account for different code formatting
    return pos.character >= prevIndent - dedents * indentSize;
  } else {
    return pos.character >= prevIndent;
  }
}

/**
 * Used to count how many times a certain substring repeats at the beginning of another string.
 * @param s Target string to check
 * @param tokenToLook Repeating token
 * @returns How many times tokenToLook repeats at the start of s
 */
function getNumberOfRepeatsAtStart(s: string, tokenToLook: string) {
  let tokenCount = 0;
  while (s.slice(tokenToLook.length * tokenCount).startsWith(tokenToLook)) {
    tokenCount += 1;
  }
  return tokenCount;
}

/**
 * Shortens the passed in s using spaces as a heuristic token split.
 * Will only save the last n tokens.
 * @param s String to shorten
 * @param n Number of "tokens" to save
 * @returns New truncated string
 */
function shortenContextOnSpaces(s: string, n: number) {
  const splitOnSpaces = s.split(" ");

  const lastElements = returnLastNElements(splitOnSpaces, n);

  return lastElements.join(" ");
}

/**
 * Returns the last n elements from the given array.
 * Will return same array if the length of array is shorter than n.
 * @param arr Target array to retrieve last n elements from
 * @param n Retrives this many elements from the end of arr
 * @returns New array of at most length n
 */
function returnLastNElements<T>(arr: T[], n: number) {
  return arr.length < n ? arr : arr.slice(-n);
}
