import { Worker } from "worker_threads";
import { ILoggingService, LogLevel } from "../logging";
import { SettingsStorage } from "../settings/settings";
import {
  CachingResultMessage,
  Message,
  RequestMessage,
  ResponseMessage,
  SettingsResponseMessage,
} from "../../workerThread/messages";
import {
  AbstractCompletionService,
  RequestResult,
} from "./abstractCompletionService";
import { ITelemetrySender } from "../telemetry/sender";
import { ENTRY_FILENAME } from "../../entry";
import { AwaitableMessageExchanger } from "../../utils/awaitableMessageExchanger";
import { ICompletionResultCallback } from "../../resultCache/completionResultCallback";
import { TelemetryEventNames, TelemetryPropertyNames } from "../../@types/telemetry"

const logPrefix = "[Worker thread] ";

const TIME_BUDGET_MS = 5000;

/** Wait for this amount of time before attempting to create a new worker thread */
const WORKER_THREAD_RECREATE_DELAY_MS = 1000;

/** Stop creating worker threads after this many retries */
const WORKER_THREAD_RETRIES_MAX = 3;

export async function initWorkerThreadCompletionService(
  settingsStorage: SettingsStorage,
  telemetry: ITelemetrySender,
  logger: ILoggingService
) {
  return new WorkerThreadLineCompletionService(
    logger,
    telemetry,
    settingsStorage
  );
}

/**
 * An implementation of AbstractCompletionService which starts up a worker thread
 * and communicates with that to infer completions.
 * The worker thread is implemented with `localLineCompletionService`.
 */
export class WorkerThreadLineCompletionService extends AbstractCompletionService {
  private worker: Worker | undefined;

  private responseAwaiter: AwaitableMessageExchanger<RequestMessage, ResponseMessage>;
  private workerThreadRetries: number = 0;

  public constructor(
    Logger: ILoggingService,
    private telemetry: ITelemetrySender,
    private settingsStorage: SettingsStorage
  ) {
    super(Logger);
    this.responseAwaiter = new AwaitableMessageExchanger<RequestMessage, ResponseMessage>(m => this.worker?.postMessage(m));
    this.worker = this.createNewWorker();
  }

  public createNewWorker(): Worker | undefined {
    let worker: Worker | undefined;
    try {
      worker = new Worker(ENTRY_FILENAME, {});
      worker.on("message", (response) => {
        this.handleMessage(<Message>response);
      });
      this.Logger.write(LogLevel.INFO, `Worker ${worker.threadId.valueOf()} has been created`);
    } catch (e) {
      this.Logger.write(LogLevel.FATAL, `Couldn't create worker: ${e}`);
      worker = undefined;
    }
    return worker;
  }

  public async request(
    requestId: number,
    context: string,
    lang: string,
    completionState: ICompletionResultCallback,
    cancellationToken: { isCancellationRequested: boolean }
  ): Promise<RequestResult> {
    const logPrefix = `[WorkerThreadLineCompletionService.request() ${requestId}] `;

    this.Logger.write(LogLevel.DEBUG, `${logPrefix} Entered`);
    const timeBudgetPromise: Promise<undefined> = new Promise(
      (_resolve, reject) =>
        setTimeout(() => {
          reject(new Error(`Operation took longer than ${TIME_BUDGET_MS}ms.`));
        }, TIME_BUDGET_MS)
    );

    const requestPromise: Promise<ResponseMessage> = (async () => {
      const response = await this.responseAwaiter.exchange(
        {
          kind: "RequestMessage",
          requestId: requestId,
          normalizedContext: context,
          lang: lang,
        }
      );

      const numAccepted = await completionState.setLineCompletions(
        response.requestId,
        context,
        response.completions,
        response.logConfidenceThreshold,
        response.lengthPenalty
      );

      // Tell worker how many completions were accepted into the cache.
      const cacheResultReply: CachingResultMessage = {
        kind: "CachingResultMessage",
        requestId: response.requestId,
        numAccepted: numAccepted
      };
      this.worker?.postMessage(cacheResultReply);
      return response;
    })();

    const result = <Message | undefined>(
      await Promise.race([requestPromise, timeBudgetPromise])
    );

    if (result === undefined) {
      this.Logger.write(
        LogLevel.INFO,
        `${logPrefix}Request took too long and was cancelled.`
      );
      return RequestResult.TimedOut;
    }

    if (result.kind !== "ResponseMessage") {
      this.Logger.write(
        LogLevel.ERROR,
        `${logPrefix}Response message was not the right kind: ${result}`
      );
      return RequestResult.Unknown;
    }

    if (cancellationToken.isCancellationRequested) {
      this.Logger.write(
        LogLevel.INFO,
        `${logPrefix}Response was recieved, but the request was cancelled.`
      );
      return RequestResult.Cancelled;
    }

    this.Logger.write(LogLevel.DEBUG, `${logPrefix}Request succeeded`);
    return RequestResult.Success;
  }
  public getFullName(): string {
    return "Line-level code completion service";
  }


  /**
   * Handle messages coming in from the worker thread, and act upon them.
   * @param msg The message.
   */
  private handleMessage(msg: Message) {
    switch (
    msg.kind // Determine what kind of message it is. They all define the 'kind' property.
    ) {
      case "LogMessage":
        this.Logger.write(msg.level, logPrefix + msg.message);
        break;
      case "RequestMessage":
        this.Logger.write(
          LogLevel.ERROR,
          logPrefix + "Request should not be sent by the worker thread."
        );
        break;
      case "ResponseMessage":
        // Match the received message back with the awaiting requester
        this.responseAwaiter.handleReceivedMessage(msg);
        break;
      case "TelemetryMessage":
        this.telemetry.sendTelemetryEvent(
          msg.eventName,
          msg.properties,
          msg.measures
        );
        break;
      case "ErrorMessage":
        this.Logger.write(LogLevel.ERROR, logPrefix + msg.error);
        break;
      case "SettingsRequestMessage":
        try {
          const result = this.settingsStorage.get(
            msg.section,
            msg.key,
            msg.default
          );
          this.Logger.write(
            LogLevel.INFO,
            `${logPrefix}Requested setting state for ${msg.section}.${msg.key} = ${result} (default is ${msg.default})`
          );
          const responseMessage: SettingsResponseMessage = {
            kind: "SettingsResponseMessage",
            section: msg.section,
            key: msg.key,
            value: result,
          };
          this.worker?.postMessage(responseMessage);
        } catch (e) {
          // Make another attempt to respond, if the actual setting wasn't sendable we should at least tell the worker thread to use the default.
          this.Logger.write(
            LogLevel.ERROR,
            `${logPrefix} Failed to send settings for section ${msg.section} to worker thread: ${e}. Trying to send default.`
          );
          try {
            const responseMessage: SettingsResponseMessage = {
              kind: "SettingsResponseMessage",
              section: msg.section,
              key: msg.key,
              value: msg.default,
            };
            this.worker?.postMessage(responseMessage);
          } catch (e) {
            this.Logger.write(
              LogLevel.ERROR,
              `${logPrefix} Sending default for ${msg.section} to worker thread also failed: ${e}.`
            );
          }
        }
        break;
      case "UnhandledRejectionMessage":
      case "UncaughtExceptionMessage":
        const numRetriesLeft = WORKER_THREAD_RETRIES_MAX - this.workerThreadRetries;

        if (numRetriesLeft > 0) {
          // Keeping track of crashed worker 
          const crashedWorker = this.worker;
          const crashedWorkerThreadId = this.worker?.threadId.valueOf();

          this.Logger.write(LogLevel.ERROR, `Worker ${crashedWorker?.threadId} has crashed. ${numRetriesLeft} retries left. Waiting for ${WORKER_THREAD_RECREATE_DELAY_MS}ms before creating a new thread and terminating crashed thread`);

          // Delay before attempting to create new worker, this prevents the extension host from crashing
          this.sleep(WORKER_THREAD_RECREATE_DELAY_MS);

          // Creating new worker thread
          this.worker = this.createNewWorker();
          this.workerThreadRetries += 1;

          this.telemetry.sendTelemetryEvent(TelemetryEventNames.WORKER_THREAD_RECREATED);

          // Terminating crashed worker after new worker is created
          crashedWorker?.terminate().then(() => this.Logger.write(LogLevel.ERROR, `Worker ${crashedWorkerThreadId} has been terminated`));
        }
        else {
          this.Logger.write(
            LogLevel.ERROR,
            `${logPrefix} Worker thread crashed after ${WORKER_THREAD_RETRIES_MAX} tries. No more retries left.`
          );
          this.telemetry.sendTelemetryEvent(TelemetryEventNames.WORKER_THREAD_RETRIES_MAX);
        }
        break;
    }
  }

  /**
 * A promise which yields execution until a number of milliseconds pass.
 * @param ms How long to wait.
 * @returns Promise which resolves after ms milliseconds.
 */
  private sleep(ms: number): Promise<void> {
    return new Promise((resolve, _reject) => setTimeout(resolve, ms));
  }
}
